const rows = $input.all().map(i => i.json);

const seuils = {
  'Diabète': { indicateur: 'Prévalence (%)', seuil: 10, dir: 'lt' },
  'Hypertension': { indicateur: 'Prévalence (%)', seuil: 25, dir: 'lt' },
  'Tuberculose': { indicateur: 'Incidence (/100 000 hab)', seuil: 20, dir: 'lt' },
  'Cancer': { indicateur: 'Survie à 5 ans (%)', seuil: 60, dir: 'gt' },
  'Maladies cardiovasculaires': { indicateur: 'Mortalité (/100 000 hab)', seuil: 100, dir: 'lt' }
};

const grouped = {};
for (const r of rows) {
  if (!r.Maladie || !r.Valeur || !r.Année) continue;
  const k = r.Maladie;
  if (!grouped[k]) grouped[k] = {};
  grouped[k][String(r.Année)] = parseFloat(r.Valeur);
}

const results = [];
for (const [maladie, data] of Object.entries(grouped)) {
  const v2019 = data['2019'], v2022 = data['2022'], v2023 = data['2023'];
  if (!v2019 || !v2023) continue;
  const evol5 = ((v2023 - v2019) / v2019 * 100).toFixed(1);
  const evol1 = v2022 ? ((v2023 - v2022) / v2022 * 100).toFixed(1) : 'N/A';
  const tendance = parseFloat(evol5) > 1 ? 'Hausse' : parseFloat(evol5) < -1 ? 'Baisse' : 'Stable';
  const ref = seuils[maladie];
  let statut = 'OK';
  if (ref) {
    const depasse = ref.dir === 'lt' ? v2023 > ref.seuil : v2023 < ref.seuil;
    if (depasse) {
      const ecart = Math.abs((v2023 - ref.seuil) / ref.seuil);
      statut = ecart > 0.2 ? 'CRITIQUE' : 'DEPASSE';
    }
  }
  results.push({ json: { maladie, val_2023: v2023, val_2019: v2019, evol_5ans_pct: evol5, evol_1an_pct: evol1, tendance, statut_OMS: statut, calcul_date: new Date().toLocaleDateString('fr-FR') } });
}
return results;

